def esc(s):
    return s.replace("'", "\\'")

def gen_items(prefix, items_list):
    lines = []
    n = len(items_list)
    for i, (ch, name, content) in enumerate(items_list, 1):
        comma = ',' if i < n else ''
        lines.append(f"        {{ id: '{prefix}-g3-{i}', chapter: '{esc(ch)}', name: '{esc(name)}', content: '{esc(content)}' }}{comma}")
    return '\n'.join(lines)

huaxue = [
('物质的量与化学计算', '阿伏加德罗常数陷阱与化学计算', '物质的量n=N/NA=m/M=V/Vm=cV。单位：摩尔mol。<br>阿伏加德罗常数NA≈6.02×10^23/mol。注意：是每摩尔物质含有的基本单元数。<br>NA题常见陷阱一：气体摩尔体积适用条件。必须是气体、必须是标准状况（0℃/101kPa或273K/1atm）。标准状况下非气体：H2O、SO3、CCl4、苯、汽油、酒精、HF、CH2Cl2、CHCl3、NO2（部分二聚）、碳原子数大于4的烃。<br>陷阱二：物质结构。质子数/电子数/中子数计算（注意同位素H/D/T）；化学键数（SiO2中每个Si与4个O成键→含4mol Si-O键；金刚石/晶体硅中每个C/Si与4个成键；P4中6mol P-P键；S8中8mol S-S键；石墨中1.5mol C-C键；苯中无C=C双键是大π键）。<br>陷阱三：电子转移。歧化反应（Cl2+H2O/NaOH→1mol Cl2转移1mol e）；归中反应；金属与酸/水反应（Na/Mg/Al失电子数由金属量计算）；电解CuCl2/NaCl/H2O；Fe/Cu与Fe3+反应（Fe+2Fe3+=3Fe2+转移2e）。<br>陷阱四：弱电解质电离与盐的水解。弱酸弱碱不能完全电离；可水解的盐溶液中离子数目改变（Fe3+、Al3+、Cu2+、NH4+、CO3^2-、S2-、F-、CH3COO-）。<br>陷阱五：溶液中的粒子数。未给溶液体积不能算物质的量；要区分溶质分子与溶剂水分子；胶体粒子是多个分子聚集体，1mol FeCl3水解得到的Fe(OH)3胶粒远小于NA。<br>陷阱六：混合物极值法。如判断1mol NO与1mol O2反应后分子数→2NO+O2=2NO2但部分NO2二聚为N2O4，分子数小于2NA。<br>陷阱七：反应的可逆性。可逆反应不能完全进行（合成氨、SO2与O2、H2+I2、酯化反应、弱酸弱碱电离）。<br>陷阱八：特殊反应。Fe与冷浓硫酸/浓硝酸钝化；Fe足量与稀HNO3生成Fe2+；Fe不足生成Fe3+；常温下Cl2与NaOH反应生成Cl-和ClO-；加热生成Cl-和ClO3-。<br>化学计算方法：质量守恒、原子/离子守恒、电荷守恒（溶液中正负电荷总数相等）、得失电子守恒（氧化还原反应）、关系式法（多步反应找关系式）、差量法（质量差/体积差/物质的量差）、极值法（极端假设判断范围）、讨论法（分类讨论多解）、十字交叉法（二元混合物）。<br>溶液pH计算：强酸pH=-lgc(H+)；强碱先求c(OH-)再求pOH=14-pH；弱酸弱碱用Ka/Kb近似；酸碱混合先判断谁过量再计算；pH=a的强酸与pH=b的强碱等体积混合，若a+b=14则恰好中和；a+b>14碱过量；a+b<14酸过量。<br>滴定计算：c标准V标准=c待测V待测。指示剂选择：强酸滴定强碱用甲基橙；强碱滴定强酸用酚酞。终点判断：最后一滴加入，指示剂颜色变化且半分钟不变。'),
('离子反应与氧化还原', '离子反应与氧化还原综合', '电解质：在水溶液或熔融状态下能导电的化合物。强电解质：强酸（HCl/HBr/HI/H2SO4/HNO3/HClO4）、强碱（NaOH/KOH/Ba(OH)2/Ca(OH)2）、大多数盐。弱电解质：弱酸、弱碱、水。<br>非电解质：在水溶液和熔融状态下都不导电的化合物。如大多数有机物、某些非金属氧化物。<br>离子方程式书写步骤：写（化学方程式）→拆（强电解质拆为离子）→删（删去左右相同离子）→查（电荷守恒、原子守恒）。<br>不能拆的物质：弱电解质、难溶物、气体、氧化物、单质、浓硫酸（浓度大时）、非电解质。<br>微溶物处理：作反应物时澄清溶液拆、浑浊不拆；作生成物时不拆。如Ca(OH)2、Ag2SO4、CaSO4、MgCO3。<br>离子共存条件：生成沉淀不能共存（AgCl/BaSO4/CaCO3/Fe(OH)3/Cu(OH)2等）；生成气体（CO2/SO2/NH3）；生成弱电解质（H2O、弱酸、弱碱）；发生氧化还原；发生双水解；发生络合反应（Fe3+与SCN-）。<br>有色离子：Fe2+（浅绿）、Fe3+（黄/棕黄）、Cu2+（蓝）、MnO4-（紫）、Cr2O7^2-（橙）、CrO4^2-（黄）、Fe(SCN)3（血红）。<br>酸性条件下不能共存：OH-、CO3^2-、HCO3-、SO3^2-、HSO3-、S2-、HS-、ClO-、F-、CH3COO-、PO4^3-、H2PO4-、HPO4^2-、SiO3^2-、AlO2-、CN-。<br>碱性条件下不能共存：H+、Fe3+、Fe2+、Cu2+、Al3+、Mg2+、NH4+、HCO3-、HSO3-、HS-、H2PO4-、HPO4^2-。<br>氧化还原离子对：强氧化性（MnO4-、NO3-(H+)、ClO-、Fe3+、Cr2O7^2-(H+)、H2O2(H+)）；强还原性（Fe2+、I-、S2-、SO3^2-、HSO3-、Br-）。两者可发生反应。特殊：Fe3+与Fe2+不反应；NO3-在中性/碱性无强氧化性。<br>双水解：Al3+与CO3^2-/HCO3-/S2-/HS-/AlO2-/ClO-；Fe3+与CO3^2-/HCO3-/AlO2-/ClO-；NH4+与AlO2-/SiO3^2-。<br>氧化还原概念：升失氧还（化合价升高、失去电子、被氧化、发生氧化反应、作还原剂）；降得还氧（化合价降低、得到电子、被还原、发生还原反应、作氧化剂）。<br>常见氧化剂：活泼非金属（Cl2/O2/Br2/F2）、含高价元素的化合物（浓H2SO4/HNO3/KMnO4/K2Cr2O7/Fe3+/HClO/MnO2）、过氧化物（H2O2/Na2O2）。<br>常见还原剂：活泼金属（K/Na/Mg/Al/Zn/Fe）、某些非金属（H2/C/S）、含低价元素的化合物（HI/HBr/H2S/SO2/Na2SO3/Na2S2O3/Fe2+/C/CO）。<br>氧化性还原性强弱判断：根据反应方程式（氧化剂>氧化产物；还原剂>还原产物）；根据活动性顺序；根据反应条件（是否加热、浓度大小）；根据反应剧烈程度；根据原电池电解池；根据元素周期律。<br>氧化还原反应配平：标价→列变→求最小公倍数→配系数→检验（原子守恒电荷守恒）。<br>离子方程式正误判断：事实（反应是否能发生、产物是否正确）、拆分（强弱电解质）、守恒（电荷原子）、配比（如Ba(OH)2与H2SO4的Ba2++2OH-+2H++SO4^2-=BaSO4↓+2H2O）、量的关系（过量/少量）。<br>与量有关的离子方程式：Al3+与NaOH（少量生成Al(OH)3；过量生成AlO2-）；Fe与稀HNO3（少量Fe生成Fe3+；过量Fe生成Fe2+）；Na2CO3与HCl（逐滴加入先生成HCO3-再生成CO2）；Ca(OH)2与NaHCO3（少量/过量不同）；Cl2与FeBr2（少量Cl2先氧化Fe2+；过量两者都氧化）。<br>陌生氧化还原反应：根据化合价升降规律判断产物、根据介质判断H+/OH-/H2O的存在。'),
('物质结构元素周期律', '元素推断与化学键', '原子结构：原子核（质子Z+中子N）+核外电子。质量数A=Z+N。<br>核素：具有一定质子和中子数的原子。同位素：同元素不同核素（同Z不同N）。<br>核外电子排布规律：能量最低、每层最多2n²、最外层≤8、次外层≤18、倒数第三层≤32。<br>电子式书写：原子（元素符号+点/×标最外层电子）；离子化合物（阳离子直接写、阴离子加括号标电荷）；共价化合物（共用电子对）；注意孤对电子不要漏写（NH3/N2/H2O等）。<br>元素周期表：7个周期（短1-3、长4-7），16个族（7主族7副族+VIII族+0族）。周期数=电子层数；主族序数=最外层电子数。<br>分区：s区（IA、IIA）、p区（IIIA-VIIA、0族）、d区（IIIB-VIII）、ds区（IB、IIB）、f区（镧系、锕系）。<br>周期律：原子半径（同周期从左到右减小；同主族从上到下增大）；金属性非金属性（同周期左→右金属性减弱非金属性增强；同主族上→下金属性增强非金属性减弱）；最高价氧化物对应水化物酸碱性（金属性越强碱性越强；非金属性越强酸性越强）；氢化物稳定性（非金属性越强越稳定）；第一电离能（总体增大趋势，IIA、VA反常）；电负性（同周期增大、同主族减小）。<br>金属性强弱判断：与水/酸反应剧烈程度；最高价氧化物水化物碱性；置换反应；阳离子氧化性（越弱金属性越强）；原电池负极金属性强。<br>非金属性强弱判断：与H2化合难易；氢化物稳定性；最高价氧化物水化物酸性；置换反应；阴离子还原性（越弱非金属性越强）。<br>元素推断突破口：周期表位置关系；原子序数关系；特殊结构（最外层电子数=次外层/最内层/电子层数等）；特殊含量（地壳中O>Si>Al>Fe；空气中N>O；人体中O>C>H）；特殊性质（半导体Si/Ge；两性Al/Be；形成化合物种类最多C；最活泼非金属F；最强碱Cs；常温液态金属Hg/非金属Br2）。<br>常见10电子微粒：分子（Ne/HF/H2O/NH3/CH4）；阳离子（Na+/Mg2+/Al3+/NH4+/H3O+）；阴离子（F-/O2-/N3-/OH-/NH2-）。<br>常见18电子微粒：分子（Ar/HCl/H2S/PH3/SiH4/F2/H2O2/N2H4/C2H6/CH3OH/CH3F/CH3NH2）；阳离子（K+/Ca2+）；阴离子（Cl-/S2-/HS-/O2^2-/P3-）。<br>化学键类型：离子键（阴阳离子静电作用，活泼金属与活泼非金属）；共价键（共用电子对，非金属之间）；金属键（金属阳离子与自由电子）。<br>共价键分类：极性键（不同原子间电子对偏移）、非极性键（相同原子间）、配位键（一方提供孤对电子另一方提供空轨道形成）。<br>σ键与π键：单键都是σ；双键一个σ一个π；三键一个σ两个π。σ键头碰头π键肩并肩。<br>键参数：键能（越大越稳定）、键长（越短越稳定）、键角（决定空间结构）。<br>等电子体：原子总数相同、价电子总数相同。具有相似结构和性质。CO/N2；CO2/N2O/CS2/SCN-；SO3/NO3-/BF3；SO2/O3；PO4^3-/SO4^2-/ClO4-；P4/CH4。'),
('化学反应原理', '反应热速率平衡综合', '反应热（焓变）：ΔH=生成物总能量-反应物总能量。ΔH<0放热；ΔH>0吸热。单位kJ/mol。<br>常见放热：燃烧、中和、金属与酸、大多数化合、自发氧化还原。常见吸热：大多数分解、C+CO2、C+H2O(g)、Ba(OH)2·8H2O+NH4Cl、水解。<br>热化学方程式书写：注明状态（s/l/g/aq）、ΔH数值与系数对应、注明温度压强（常温常压可不）、ΔH正负号不能省略。<br>燃烧热：1mol纯物质完全燃烧生成稳定氧化物放出的热量。H→H2O(l)、C→CO2(g)、S→SO2(g)、N→N2(g)。<br>中和热：强酸强碱稀溶液生成1mol H2O的反应热。ΔH=-57.3kJ/mol。弱酸弱碱电离吸热使数值偏小；浓溶液放热更多。<br>盖斯定律：反应热只与始态终态有关，与路径无关。多步反应ΔH相加。<br>反应速率：v=Δc/Δt。单位mol/(L·s)或mol/(L·min)。不同物质速率比=系数比。<br>影响速率因素：浓度（增大速率增大；固体/纯液体浓度不变无影响）、温度（升温速率增大）、压强（气体反应，加压等效于浓缩）、催化剂（降低活化能显著增大正逆速率）、其他（光照/电磁波/超声波/溶剂/反应物接触面积）。<br>活化能Ea：活化分子平均能量-反应物平均能量。催化剂降低Ea。<br>化学平衡标志：v正=v逆（同一物质消耗速率=生成速率；不同物质速率比=系数比但方向相反）；各物质浓度/质量/体积分数/物质的量分数不变；颜色不变（有颜色物质）；密度/平均分子量等视情况。<br>平衡移动（勒夏特列原理）：改变条件平衡向减弱这种改变的方向移动。<br>影响平衡的因素：浓度（增大反应物或减小生成物→正向）、温度（升温→吸热方向）、压强（加压→气体体积减小方向；等体反应不移动）、催化剂（同等改变正逆速率不移动）。<br>平衡常数K：K=生成物浓度幂/反应物浓度幂。只与温度有关。K越大正向进行程度越大。固体/纯液体不写入。逆向反应K\'=1/K；反应加倍K\'=K^n。<br>平衡三段式：起/始-转/变-平/衡。设变化量为x，根据系数关系求各物质平衡浓度。<br>平衡转化率：α=已反应/初始×100%。两种反应物增加一种浓度，另一种转化率增大而自身转化率减小。<br>等效平衡：恒温恒容等体积反应→等效转化后各物质起始量相同则等效；恒温恒容不等体积→各物质起始量相同才全等；恒温恒压→等效转化后比例相同即等效。<br>反应方向判断：ΔH<0有利于自发；ΔS>0有利于自发。综合判据ΔG=ΔH-TΔS<0则自发。<br>平衡图像分析：v-t图（浓度/温度/压强/催化剂变化）、n-t/c-t图（拐点先到先平衡说明温度高压强大）、平衡移动图（坐标含T/P时作辅助线判断）。'),
('水溶液离子平衡', '三大守恒与离子浓度大小比较', '电解质溶液：强电解质完全电离；弱电解质部分电离，存在电离平衡；可水解的盐促进水电离；酸碱抑制水电离。<br>水的电离：H2O⇌H++OH-。Kw=c(H+)·c(OH-)=10^-14（25℃），10^-12（100℃）。Kw只与温度有关。<br>pH=-lgc(H+)；pOH=-lgc(OH-)；pH+pOH=14（25℃）。<br>电离平衡常数：弱酸HA⇌H++A-，Ka=c(H+)·c(A-)/c(HA)；弱碱BOH⇌B++OH-，Kb=c(B+)·c(OH-)/c(BOH)。Ka/Kb越大越强。<br>盐类水解：有弱才水解，越弱越水解，谁强显谁性，都强显中性。<br>水解规律：强酸强碱盐（NaCl/KNO3）→中性；强酸弱碱盐（NH4Cl/AlCl3/CuSO4）→酸性；强碱弱酸盐（CH3COONa/Na2CO3/NaF）→碱性；弱酸弱碱盐→看阴阳离子水解程度相对强弱。<br>多元弱酸根分步水解，第一步为主。Na2CO3水解：CO3^2-+H2O⇌HCO3-+OH-（主）；HCO3-+H2O⇌H2CO3+OH-（次）。<br>水解影响因素：升温促进水解、稀释促进水解（浓度减小水解程度增大）、加入酸碱抑制或促进。<br>离子浓度大小比较：单一溶液先判断溶质再分析电离水解主次。Na2CO3：c(Na+)>c(CO3^2-)>c(OH-)>c(HCO3-)>c(H+)；NaHCO3：水解>电离→碱性，c(Na+)>c(HCO3-)>c(OH-)>c(H+)>c(CO3^2-)；CH3COONa：c(Na+)>c(CH3COO-)>c(OH-)>c(H+)；NH4Cl：c(Cl-)>c(NH4+)>c(H+)>c(OH-)。<br>三大守恒：电荷守恒（正负电荷总数相等，如Na2CO3：c(Na+)+c(H+)=2c(CO3^2-)+c(HCO3-)+c(OH-)）；物料守恒（某元素原子守恒，如Na2CO3：c(Na+)=2[c(CO3^2-)+c(HCO3-)+c(H2CO3)]）；质子守恒（水电离的H+与OH-守恒，Na2CO3：c(OH-)=c(H+)+c(HCO3-)+2c(H2CO3)）。<br>酸碱混合溶液：先反应后判断溶质及其量比，再比较电离与水解主次。<br>等浓度CH3COOH与CH3COONa混合：电离>水解→酸性；等浓度NH3·H2O与NH4Cl混合：电离>水解→碱性；等浓度HCN与NaCN混合：水解>电离→碱性。<br>pH之和为14的酸碱等体积混合：谁弱显谁性（弱酸过量显酸，弱碱过量显碱）。<br>盐溶液蒸干产物：易水解的盐（FeCl3蒸干得Fe(OH)3灼烧得Fe2O3；AlCl3类似；Na2CO3/Na2SO3蒸干得本身但Na2SO3易被氧化为Na2SO4）。<br>离子浓度比较方法：先确定溶质→判断酸碱性→确定主次（电离/水解）→三大守恒列方程→求解不等式关系。'),
('电化学', '原电池电解池综合', '原电池：将化学能转化为电能的装置。形成条件：活泼性不同两电极、电解质溶液（或熔融）、闭合回路、自发氧化还原反应。<br>电极判断：负极（较活泼金属、失电子、氧化反应、电子流出、电流流入、阴离子移向、溶解/质量减小）；正极（较不活泼金属或非金属、得电子、还原反应、电子流入、电流流出、阳离子移向、析出气体或金属）。<br>电极反应书写：负极写氧化（失e）；正极写还原（得e）。两式相加得总反应。注意介质（酸性用H+和H2O、碱性用OH-和H2O、熔融盐/氧化物用相应离子）。<br>常见原电池：锌铜原电池（Zn+H2SO4=ZnSO4+H2）、铅蓄电池（Pb+PbO2+2H2SO4=2PbSO4+2H2O）、氢氧燃料电池（2H2+O2=2H2O）、甲烷/甲醇燃料电池（碱性介质产物CO3^2-）、纽扣电池（Zn+Ag2O=ZnO+2Ag）、锂离子电池。<br>燃料电池：负极燃料氧化，正极O2还原。注意介质不同产物不同：酸性生成H2O、碱性生成OH-/CO3^2-、熔融碳酸盐生成CO3^2-、固体氧化物电解质生成O2-。<br>电解池：将电能转化为化学能的装置。两电极（阴极与电源负极相连得e还原；阳极与电源正极相连失e氧化）。<br>离子放电顺序：阴极（得电子能力强先得）：Ag+>Hg2+>Fe3+>Cu2+>H+(酸)>Pb2+>Sn2+>Fe2+>Zn2+>H+(水)>Al3+>Mg2+>Na+>Ca2+>K+；阳极（失电子能力强先失）：活性电极（除Pt/Au外的金属，自身失电子溶解）>S2->I->Br->Cl->OH->含氧酸根>F-。<br>电解四大类型：电解水（H2SO4/NaOH/Na2SO4等）→2H2O=2H2↑+O2↑；电解电解质本身（CuCl2/HCl）→CuCl2=Cu+Cl2↑；放氢生碱（NaCl等活泼金属无氧酸盐）→2NaCl+2H2O=2NaOH+H2↑+Cl2↑；放氧生酸（CuSO4/AgNO3等不活泼金属含氧酸盐）→2CuSO4+2H2O=2Cu+O2↑+2H2SO4。<br>常见电解应用：电解饱和食盐水（氯碱工业，制Cl2/H2/NaOH）；电解精炼铜（粗铜作阳极精铜作阴极CuSO4溶液）；电镀（待镀金属作阴极镀层金属作阳极含镀层离子溶液）；电解法冶炼活泼金属（电解熔融NaCl制Na、熔融MgCl2制Mg、熔融Al2O3加冰晶石制Al）。<br>电化学计算：电子守恒（串联电路各电极电子数相等）。关系：n(e)=n(金属)/化合价=2n(H2)=n(Cl2)=2n(Cu)=4n(O2)。电量Q=It=nF（F=96500C/mol）。<br>金属腐蚀：化学腐蚀（金属与接触物质直接反应）、电化学腐蚀（形成原电池，更普遍更快）。电化学腐蚀分析氢腐蚀（酸性较强环境，2H++2e=H2）和吸氧腐蚀（中性/弱酸性/碱性，O2+2H2O+4e=4OH-，最普遍）。<br>金属防护：改变金属内部结构（不锈钢）、覆盖保护层（涂油/喷漆/电镀/热镀/搪瓷/氧化膜）、电化学保护（牺牲阳极的阴极保护法-原电池原理；外加电流的阴极保护法-电解池原理）。<br>新型电池分析：判断正负极（化合价/反应类型）、书写电极反应（注意介质）、分析离子移动（阳离子向正极阴离子向负极）、判断pH变化（结合总反应和电极反应）。'),
('有机化学基础', '官能团性质与有机合成推断', '有机物分类：烃（烷/烯/炔/芳香烃）、烃的衍生物（卤代烃/醇/酚/醛/酮/羧酸/酯/醚/胺/酰胺）、糖类/油脂/蛋白质/核酸、高分子化合物。<br>同分异构：碳链异构、位置异构、官能团异构（类别异构如醇与醚/醛与酮/羧酸与酯/葡萄糖与果糖）。书写方法：碳链缩短法、取代基插入法、定一移二法。<br>重要官能团及性质：碳碳双键/三键（加成反应、加聚、氧化使KMnO4褪色）；苯环（取代/加成/侧链被氧化）；卤原子-X（水解生成醇、消去生成烯）；羟基-OH（醇：置换/消去/取代/氧化/酯化；酚：弱酸性/取代/显色/易氧化）；醛基-CHO（氧化成酸、还原成醇、银镜反应/斐林反应检验）；羧基-COOH（酸的通性/酯化反应）；酯基-COOR（水解酸性/碱性）；氨基-NH2（碱性、缩聚）；肽键（-CO-NH-水解）。<br>重要有机反应类型：取代（烷烃卤代/苯的卤代硝化磺化/醇的卤代/酯化/酯水解/卤代烃水解/酚的取代）；加成（烯/炔/苯环/醛/酮与H2/X2/HX/H2O/HCN加成）；消去（醇/卤代烃在一定条件下消去H2O/HX生成不饱和键）；氧化（燃烧/醇氧化/醛氧化/烯被强氧化剂氧化/酚被氧化）；还原（烯/炔/苯/醛/酮与H2加成；硝基还原为氨基）；加聚（含双键三键单体聚合成高分子）；缩聚（二元醇+二元酸/羟基酸/氨基酸/酚醛缩聚）；水解（卤代烃/酯/二糖多糖/蛋白质/油脂）；显色（酚+FeCl3显紫色；淀粉+I2显蓝色；蛋白质+浓HNO3变黄）。<br>有机反应条件：光照（烷烃取代）；Ni/加热加压（加H2）；浓硫酸/加热（酯化/消去/硝化/酯化缩聚）；稀硫酸/加热（酯/糖/蛋白质水解）；NaOH水溶液/加热（卤代烃水解/酯水解）；NaOH醇溶液/加热（卤代烃消去）；Cu/Ag/加热（醇催化氧化）；银氨溶液/加热、新制Cu(OH)2/加热（醛氧化检验）；KMnO4/H+（烯/炔/苯的同系物/醇/醛/酚氧化）。<br>有机推断突破口：特殊反应条件（浓硫酸/加热→酯化/消去/硝化；NaOH水溶液→水解；NaOH醇溶液→消去；银氨→醛）；特征现象（溴水褪色→烯/炔/酚；FeCl3显色→酚；银镜→醛；砖红色沉淀→醛/甲酸/甲酸酯/葡萄糖；新制Cu(OH)2溶解→酸；Na反应放H2→醇/酚/羧酸；NaHCO3/Na2CO3放CO2→羧酸）；特征转化关系（A→B→C连续氧化常为醇→醛→酸或烯→醛→酸；A+B→C+D+H2O常为酯化/取代）；特殊数据（相对分子质量/分子式/不饱和度Ω=(2C+2+N-H-X)/2）；信息给予的新反应。<br>有机合成思路：逆推法（由目标产物倒推原料）、正推法、综合法。关键是官能团的引入/消除/转变/保护。<br>官能团引入：引入-OH（烯加水/醛酮加氢/卤代烃水解/酯水解）；引入-X（烯炔加HX/X2/醇卤代/烷苯取代）；引入C=C（醇消去/卤代烃消去/炔不完全加成）；引入-CHO（醇氧化/烯催化氧化）；引入-COOH（醛氧化/酯酸性水解/苯的同系物被强氧化）；引入-COOR（酯化反应）。<br>官能团消除：双键/三键加氢、醛酮加氢、醇消去、醇氧化。<br>官能团保护：酚羟基（先酯化后水解）、醛基（先加成后氧化）、氨基（先质子化后中和）。<br>同分异构体数判断：对称法、等效氢法、替换法（如二氯苯与四氯苯数目相同）。<br>高聚物单体判断：加聚产物断双键找单体；缩聚产物断肽键/酯基加-OH和-H找单体。'),
('化学工艺流程', '原料预处理与物质分离提纯', '化学工艺流程：以真实工业生产为背景，以化学方程式为核心，结合实验、计算、理论解释的综合题。<br>常见原料：矿石（金属矿、非金属矿）、海水、空气、工业废料、石油分馏/裂解产品、农副产品。<br>原料预处理方法：研磨/粉碎（增大接触面积加快反应）；煅烧/焙烧/灼烧（高温分解、氧化、除去杂质如C/S/有机物）；浸取（水浸/酸浸/碱浸-溶解目标成分）；搅拌（加快溶解反应）；加热（加快反应/促进溶解/除去易挥发杂质）。<br>反应条件控制：温度（过高分解/挥发/氧化/副反应；过低速率小）；pH（防止水解/控制沉淀生成/影响氧化还原性）；浓度（影响反应速率和产率）；压强（对气体反应）；催化剂（选择和使用条件）。<br>控制温度的目的：加快反应速率、促进或抑制水解、使某些物质挥发、防止副反应、使某物质分解、控制溶解度差异。<br>控温方法：水浴加热（温和均匀≤100℃）、油浴（>100℃）、冰水浴（降温冷凝/减少挥发）、加热回流（防止反应物挥发损失）。<br>pH控制：调节pH使某金属离子沉淀为氢氧化物分离；抑制或促进盐的水解；提供酸碱性介质影响氧化还原性。常用调节试剂：稀酸/稀碱/难溶金属氧化物/氢氧化物/碳酸盐（如CuO/Cu(OH)2/CuCO3/Cu2(OH)2CO3用于Cu2+溶液除Fe3+）。<br>除杂方法：转化法（将杂质转化为目标产物或易分离物）、沉淀法（生成难溶物过滤除去）、挥发法（加热除去挥发物）、萃取分液（有机溶剂提取水中物质）、蒸馏/分馏（分离沸点不同液体混合物）、升华（分离易升华固体如I2）、结晶（蒸发结晶/冷却结晶分离溶解度受温度影响不同物质）、盐析（加轻金属盐使蛋白质析出）。<br>分离提纯综合：过滤（常压/减压/热过滤）、蒸发浓缩（除去部分溶剂提高浓度）、冷却结晶（趁热过滤防止其他物质析出）、洗涤（水洗/乙醇洗减少溶解损失，洗去杂质离子）、干燥（除去水分）。<br>常见离子检验：Fe2+（KSCN无现象加氯水变血红色）、Fe3+（KSCN溶液变血红色）、NH4+（加NaOH加热产生使湿润红色石蕊试纸变蓝气体）、SO4^2-（稀HCl酸化后加BaCl2白色沉淀）、Cl-（稀HNO3酸化加AgNO3白色沉淀）、CO3^2-（加稀HCl产生使澄清石灰水变浑浊无味气体）。<br>产率计算：实际产量/理论产量×100%。理论产量根据限量反应物计算。<br>纯度计算：主要成分质量/样品总质量×100%。常用滴定法/沉淀法/气体法。<br>流程评价：绿色化学（原子利用率/循环使用/无污染物）、能耗/成本/设备腐蚀、原料是否易得、产物是否纯净、副产物利用、三废处理。<br>循环利用物质：母液（含未反应原料/副产品）、催化剂、溶剂、反应中间产物。<br>常见化工：氯碱工业、硫酸工业、硝酸工业、合成氨、海水提溴、海水提镁、侯氏制碱（联合制碱）、金属冶炼（Fe/Cu/Al/Mg/Na）、硅工业、石油化工、化肥生产。'),
('化学实验综合', '装置连接与实验操作评价', '常见仪器：试管/烧杯/烧瓶（圆底/平底/蒸馏）、锥形瓶、蒸发皿、坩埚、酒精灯、酒精喷灯、量筒、滴定管（酸式带玻璃活塞/碱式带橡胶管）、容量瓶、托盘天平、电子天平、分液漏斗（球形/梨形）、长颈漏斗、玻璃棒、漏斗、干燥管（U形/球形）、洗气瓶、冷凝管（直形/球形/蛇形）、牛角管、胶头滴管、温度计、铁架台/铁夹/铁圈、石棉网、泥三角、试管夹、坩埚钳、研钵、药匙、镊子。<br>基本操作：药品取用（固体块状一横二放三慢竖；粉末一斜二送三直立；液体标签向手心瓶口紧挨）、物质加热（试管外壁干燥先预热；烧杯烧瓶垫石棉网；蒸发坩埚直接加热）、溶解（搅拌/加热/粉碎促溶）、过滤（一贴二低三靠、洗涤沉淀方法）、蒸发（蒸发皿、玻璃棒搅拌防溅、余热蒸干不要完全蒸干）、蒸馏（沸石防暴沸、温度计水银球位置、冷凝水下进上出）、萃取分液（萃取剂不溶于水且密度不同、溶质在其中溶解度大；分液漏斗使用前检漏、先放下层后倒上层）、结晶（蒸发结晶用于溶解度受温度小的；冷却结晶用于溶解度受温度大的；重结晶提纯）、溶液配制（一定质量分数：计算称量溶解；一定物质的量浓度：计算称量溶解冷却转移洗涤定容摇匀；容量瓶检漏）、滴定（润洗、滴定管装液排气泡调液面读数、左手控制活塞或捏玻璃球、右手摇瓶、眼睛注视锥形瓶内颜色变化、终点判断最后一滴颜色变化半分钟不变、多次实验取平均值）。<br>装置连接顺序：一般是气体发生装置→除杂装置→干燥装置→主体实验装置→尾气处理装置。<br>气体制备：O2（2KMnO4=K2MnO4+MnO2+O2↑加热；2H2O2=2H2O+O2↑MnO2催化；2KClO3=2KCl+3O2↑MnO2加热）；H2（Zn+H2SO4=ZnSO4+H2↑）；CO2（CaCO3+2HCl=CaCl2+H2O+CO2↑不能用稀硫酸因CaSO4微溶）；Cl2（MnO2+4HCl(浓)=MnCl2+Cl2↑+2H2O加热；或2KMnO4+16HCl=2KCl+2MnCl2+5Cl2↑+8H2O不加热）；NH3（2NH4Cl+Ca(OH)2=CaCl2+2NH3↑+2H2O加热；或浓氨水加生石灰/NaOH固体/碱石灰）；SO2（Na2SO3+H2SO4(浓)=Na2SO4+SO2↑+H2O）；NO（3Cu+8HNO3(稀)=3Cu(NO3)2+2NO↑+4H2O）；NO2（Cu+4HNO3(浓)=Cu(NO3)2+2NO2↑+2H2O）；C2H4（C2H5OH→C2H4↑+H2O浓硫酸170℃，加沸石防暴沸，温度计插入液体）；C2H2（CaC2+2H2O→Ca(OH)2+C2H2↑，用饱和食盐水减慢速率）。<br>气体除杂干燥：除杂用洗气瓶（长进短出）或干燥管（大进小出）。干燥剂选择：酸性干燥剂（浓硫酸/P2O5/硅胶-不能干燥碱性气体和强还原性气体H2S/HI等）；碱性干燥剂（碱石灰/NaOH固体-不能干燥酸性气体）；中性干燥剂（无水CaCl2-不能干燥NH3因生成络合物）。<br>气体收集：排水法（不溶/微溶于水且不反应：O2/H2/N2/NO/CO/C2H4/C2H2）；向上排空气（密度>空气：O2/CO2/SO2/Cl2/HCl/NO2/Cl2）；向下排空气（密度<空气：H2/NH3/CH4）。注意NO只能排水；NO2不能排水；Cl2可用排饱和食盐水。<br>尾气处理：燃烧法（CO/H2/CH4等）；吸收法（HCl/NH3用防倒吸装置如倒扣漏斗/球形干燥管/安全瓶；Cl2/SO2/NO2用NaOH吸收）；收集法（气球/塑料袋）。<br>物质检验：固体检验（观察颜色、溶解性、酸碱性、特征反应）；液体检验（颜色、密度、互溶性、pH、特征反应）；离子检验（注意排除干扰）；有机物检验（官能团特征反应）。<br>定量实验：滴定实验（酸碱中和滴定/氧化还原滴定/沉淀滴定-注意指示剂选择终点判断误差分析）；测定气体体积（排水法注意温度压强校正、读数时使量气管和水准管液面相平）；测定沉淀质量（洗涤干净、恒重操作）。<br>实验评价：实验原理是否科学合理、操作是否简单安全、装置是否简单、现象是否明显、误差是否小、是否环保（绿色化学）、是否经济。<br>实验设计原则：科学性、安全性、可行性、简约性。<br>安全操作：防爆炸（点燃气体先验纯）、防暴沸（加沸石/碎瓷片）、防倒吸（加热排水法收集先撤导管后撤灯；用安全瓶/防倒吸装置）、防中毒（有毒气体在通风橱操作、尾气处理）、防堵塞、防污染。<br>实验中冰水作用：冷凝反应物/产物、降低某物质溶解度使其析出、降低温度减少挥发、减少副反应。<br>实验中乙醇等有机溶剂洗涤作用：减少产品溶解损失、除去水溶性杂质、易挥发便于干燥。<br>趁热过滤目的：防止某物质因降温结晶析出导致损失或引入杂质。')
]

with open(outpath, 'a', encoding='utf-8') as f:
    f.write("    '化学': [\n")
    f.write(gen_items('huaxue', huaxue))
    f.write("\n    ],\n")

